var (
	// ANSI is a conservative, portable SQL dialect: unquoted identifiers, "?"
	// placeholders, and SQL:2003 identity columns. It is the default used by the
	// package-level DSL helpers.
	ANSI Dialect = ansiDialect{}
	// Postgres targets PostgreSQL: double-quoted identifiers, "$n" placeholders,
	// bigserial primary keys, and native jsonb / array / uuid types.
	Postgres Dialect = postgresDialect{}
	// MySQL targets MySQL/MariaDB: backtick-quoted identifiers, "?" placeholders,
	// AUTO_INCREMENT primary keys, and inline ENUM types.
	MySQL Dialect = mysqlDialect{}
	// SQLite targets SQLite: double-quoted identifiers, "?" placeholders, and
	// INTEGER PRIMARY KEY AUTOINCREMENT.
	SQLite Dialect = sqliteDialect{}
)

types.signature:
type Migration struct {
	// Version orders the migration and uniquely identifies it. A common
	// convention is a UTC timestamp such as 20240117153000.
	Version uint64

	// Name is a short human readable label, e.g. "create_users".
	Name string

	// Up applies the migration. Optional if UpSQL is set.
	Up MigrateFunc
	// Down reverses the migration. Optional; a migration with neither Down nor
	// DownSQL is irreversible and cannot be rolled back.
	Down MigrateFunc

	// UpSQL / DownSQL provide the directions as raw SQL. Ignored for a
	// direction whose Go function is non-nil.
	UpSQL   string
	DownSQL string
}

